		&lt;li&gt;अर्थात्&amp;ndash; ए, ऐ (अ + इ)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;कण्ठोष्ठ (कण्ठोष्ठ् वर्ण)&amp;ndash; &amp;quot;ओदोतो कण्ठोष्ठ्म्&amp;quot;
	&lt;ul&gt;
		&lt;li&gt;अर्थात् ओ, औ (अ + उ)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;दन्तोष्ठ (दन्तोष्ठ्य वर्ण)&amp;ndash; &amp;quot;वकारस्य दन्तोष्ठम्&amp;quot;
	&lt;ul&gt;
		&lt;li&gt;अर्थात् व् का उच्चारण स्थान दन्त है।&lt;/li&gt;
	&lt;/ul&gt;
